import { Mic, MicOff } from 'lucide-react';
import { clsx } from 'clsx';

interface MicButtonProps {
  isListening: boolean;
  onClick: () => void;
  disabled?: boolean;
}

export function MicButton({ isListening, onClick, disabled }: MicButtonProps) {
  return (
    <div className="relative group">
      {/* Outer Glow */}
      <div 
        className={clsx(
          "absolute inset-0 rounded-full blur-xl transition-all duration-700 pointer-events-none",
          isListening ? "bg-red-500/40 animate-pulse-slow scale-150" : "bg-indigo-500/20 group-hover:bg-indigo-500/40 scale-110"
        )}
      />
      
      {/* Button */}
      <button
        onClick={onClick}
        disabled={disabled}
        className={clsx(
          "relative z-10 w-24 h-24 rounded-full flex items-center justify-center transition-all duration-300 border-2 shadow-2xl",
          isListening 
            ? "bg-red-500/20 border-red-400 text-red-400 scale-105" 
            : "bg-white/5 border-indigo-500/50 text-indigo-400 hover:scale-105 hover:bg-white/10 hover:border-indigo-400",
          disabled && "opacity-50 cursor-not-allowed hover:scale-100"
        )}
      >
        {isListening ? <Mic size={40} className="animate-pulse" /> : <MicOff size={40} />}
      </button>
    </div>
  );
}
